<script setup>import{computed}from'vue';import{useRoute}from'vue-router';import{useCompanyStore}from'../stores/company';const route=useRoute(),company=useCompanyStore();const terms=computed(()=>route.name==='Terms');const title=computed(()=>terms.value?'Términos de postulación':'Política de privacidad');const content=computed(()=>terms.value?company.settings?.terminosPostulacion:company.settings?.politicaPrivacidad);const version=computed(()=>terms.value?company.settings?.versionTerminos:company.settings?.versionPoliticaPrivacidad)</script>
<template><div class="mx-auto max-w-3xl px-4 py-14"><h1 class="font-display text-3xl font-bold">{{title}}</h1><p v-if="version" class="mt-2 text-sm text-stone-400">Versión {{version}}</p><article class="mt-8 whitespace-pre-line rounded-2xl bg-white p-7 leading-8 text-stone-600 shadow-sm">{{content||'Este documento se publicará próximamente.'}}</article></div></template>
